/**
 * @name aiohttp static file path traversal via request path to filesystem
 * @description Track flow from request URL/path parameters to filesystem access in aiohttp static file handlers without proper normalization or boundary checks.
 * @kind path-problem
 * @problem.severity error
 * @id py/aiohttp-static-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-023
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.ApiGraphs
import semmle.python.Concepts

/**
 * Configuration: source = request path info; sink = filesystem path arguments.
 */
module AiohttpStaticTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(API::CallNode call |
      // request.match_info["name"] or request.rel_url.path, etc.
      call = API::moduleImport("aiohttp.web_request").getMember("Request").getMember(["match_info", "rel_url", "path"]).getACall() and
      source = call
    ) or
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(FileSystemAccess fa |
      sink = fa.getAPathArgument()
    )
  }
}

module AiohttpStaticTraversalFlow = TaintTracking::Global<AiohttpStaticTraversalConfig>;
import AiohttpStaticTraversalFlow::PathGraph

from AiohttpStaticTraversalFlow::PathNode source, AiohttpStaticTraversalFlow::PathNode sink
where AiohttpStaticTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled path flows into filesystem access, potential path traversal.", source.getNode(), "user-controlled path"
